// Extrai o token e define datas de ontem
const loginData = $input.first().json;
const token = loginData.accessToken;

if (!token) {
  throw new Error('Login RHiD falhou - token não retornado: ' + JSON.stringify(loginData));
}

// Data de ontem no formato YYYY-MM-DD
const hoje = new Date();
const ontem = new Date(hoje);
ontem.setDate(hoje.getDate() - 1);

const dataIni = ontem.toISOString().slice(0, 10);
const dataFinal = ontem.toISOString().slice(0, 10);

return [{
  json: {
    token,
    dataIni,
    dataFinal,
    bearerHeader: `Bearer ${token}`
  }
}];

// Combina token com lista de empresas
const tokenData = $('Extrair Token e Datas').first().json;
const empresasData = $input.first().json;

const empresas = empresasData.records || [];

if (empresas.length === 0) {
  throw new Error('Nenhuma empresa retornada pelo RHiD');
}

console.log(`[RHiD] ${empresas.length} empresa(s) encontrada(s)`);

// Retorna uma linha por empresa, com token e datas
return empresas.map(empresa => ({
  json: {
    token: tokenData.token,
    bearerHeader: tokenData.bearerHeader,
    dataIni: tokenData.dataIni,
    dataFinal: tokenData.dataFinal,
    empresa_rhid_id: empresa.id,
    empresa_rhid_nome: empresa.name,
    empresa_cnpj: empresa.cnpj
  }
}));

// Para cada pessoa da empresa, monta chamada de apuração
const empresaData = $('Preparar Loop por Empresa').first().json;
const pessoasData = $input.first().json;

const pessoas = (pessoasData.records || []).filter(p => 
  p.idCompany === empresaData.empresa_rhid_id || !p.idCompany
);

console.log(`[RHiD] Empresa ${empresaData.empresa_rhid_nome}: ${pessoas.length} pessoa(s)`);

if (pessoas.length === 0) {
  return [{ json: { skip: true, empresa: empresaData.empresa_rhid_nome } }];
}

return pessoas.map(pessoa => ({
  json: {
    token: empresaData.token,
    bearerHeader: empresaData.bearerHeader,
    dataIni: empresaData.dataIni,
    dataFinal: empresaData.dataFinal,
    empresa_rhid_id: empresaData.empresa_rhid_id,
    empresa_rhid_nome: empresaData.empresa_rhid_nome,
    empresa_cnpj: empresaData.empresa_cnpj,
    pessoa_id: pessoa.id,
    pessoa_nome: pessoa.name,
    pessoa_cpf: String(pessoa.cpf || '').replace(/\D/g, ''),
    pessoa_matricula: pessoa.registration || null
  }
}));

// Transforma dados de apuração do RHiD para formato do ERP Orbe
const pessoaData = $('Preparar Loop por Pessoa').first().json;
const apuracaoData = $input.first().json;

// Skip se não tem dados
if (pessoaData.skip) return [];

// A apuração pode retornar array ou objeto
const registros = Array.isArray(apuracaoData) 
  ? apuracaoData 
  : (apuracaoData.records || apuracaoData.data || [apuracaoData]).filter(Boolean);

if (registros.length === 0) {
  console.log(`[RHiD] Sem apuração para ${pessoaData.pessoa_nome} em ${pessoaData.dataIni}`);
  return [];
}

// Função para converter tempo decimal ou string para HH:MM:SS
const parseTime = (v) => {
  if (!v && v !== 0) return null;
  const s = String(v).trim();
  if (!s) return null;
  if (/^\d{1,2}:\d{2}(:\d{2})?$/.test(s)) {
    const p = s.split(':');
    return `${p[0].padStart(2,'0')}:${p[1]}:${p[2] || '00'}`;
  }
  const num = parseFloat(s);
  if (!isNaN(num) && num >= 0 && num < 1) {
    const t = Math.round(num * 86400);
    const h = Math.floor(t / 3600);
    const m = Math.floor((t % 3600) / 60);
    const sc = t % 60;
    return `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(sc).padStart(2,'0')}`;
  }
  return null;
};

const parseDate = (v) => {
  if (!v) return null;
  const s = String(v).trim();
  // Formato DD/MM/YYYY
  const slash = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2,4})$/);
  if (slash) {
    const [,d,m,y] = slash;
    return `${y.length===2?'20'+y:y}-${m.padStart(2,'0')}-${d.padStart(2,'0')}`;
  }
  // Já é ISO
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  return null;
};

return registros.map(reg => ({
  json: {
    // Identificação
    empresa_rhid_nome: pessoaData.empresa_rhid_nome,
    empresa_cnpj: pessoaData.empresa_cnpj,
    pessoa_nome: pessoaData.pessoa_nome,
    pessoa_cpf: pessoaData.pessoa_cpf,
    pessoa_matricula: pessoaData.pessoa_matricula,
    // Dados de ponto
    data: parseDate(reg.date || reg.data || pessoaData.dataIni),
    entrada: parseTime(reg.firstEntry || reg.entrada || reg.in),
    saida_almoco: parseTime(reg.firstExit || reg.saida_almoco || reg.lunchOut),
    retorno_almoco: parseTime(reg.secondEntry || reg.retorno_almoco || reg.lunchIn),
    saida: parseTime(reg.lastExit || reg.saida || reg.out),
    horas_trabalhadas: parseTime(reg.workedHours || reg.horas_trabalhadas),
    hora_extra: parseTime(reg.extraHours || reg.hora_extra),
    falta: reg.absence || reg.falta || null,
    atraso: reg.delay || reg.atraso || null,
    // Status
    status: 'PENDENTE_PROCESSAMENTO',
    origem: 'rhid_api',
    // Raw para debug
    _raw: reg
  }
}));

// Log de sucesso
const result = $input.first().json;
console.log('[RHiD→ERP] Sucesso:', JSON.stringify(result));
return $input.all();

// Log de registros sem data (pular silenciosamente)
const item = $input.first().json;
console.log('[RHiD] Registro ignorado - sem data:', item.pessoa_nome);
return [];
